// gen_commands reads a schema YAML file and generates Cobra command boilerplate
// for each operation, writing the output to the specified Go file.
//
// Usage: go run scripts/gen_commands/main.go <schema.yaml> <output.go>
//
// The generated file defines NewXxxCommand() which wires all operations as
// sub-commands under a parent command. Each generated command:
//   - Reads path parameters as required --flags
//   - Reads query parameters as optional --flags (typed from schema)
//   - For POST/PUT/PATCH operations, generates typed --flags from the request body schema
//   - Falls back to --body for raw JSON input (advanced)
//   - Calls handlers.Dispatch with method, URL template, params, etc.
//
// This script is run in CI whenever the schema changes.
package main

import (
	"bytes"
	"fmt"
	"go/format"
	"os"
	"text/template"

	"github.com/FabianSchurig/bitbucket-cli/scripts/internal/spec"
)

// ─── Template data types ──────────────────────────────────────────────────────

// CommandData holds the data for a single generated Cobra command.
type CommandData struct {
	OperationID string
	Use         string
	Short       string
	Long        string
	Method      string
	Path        string
	Flags       []FlagData
	BodyFields  []spec.BodyField
	HasBody     bool
	Paginated   bool
}

// FlagData holds the data for a single CLI flag.
type FlagData struct {
	Name     string
	GoName   string
	GoType   string
	Default  string
	Usage    string
	Required bool
	In       string
	RawName  string
}

// FileData holds the complete template data for one generated file.
type FileData struct {
	SchemaPath   string
	CommandName  string // e.g., "PR", "Hooks" — used in function name NewXxxCommand()
	CommandUse   string // e.g., "pr", "hooks" — Cobra Use field
	CommandShort string // Cobra Short field
	CommandLong  string // Cobra Long field
	Commands     []CommandData
}

// ─── Conversion: spec.OperationDef → CommandData ──────────────────────────────

func paramToFlag(p spec.ParamDef) FlagData {
	gt := spec.GoType(p.Type)
	return FlagData{
		Name:     spec.FlagName(p.Name),
		GoName:   spec.ToGoName(p.Name),
		GoType:   gt,
		Default:  spec.DefaultValue(gt),
		Usage:    spec.DescribeParam(p),
		Required: p.Required,
		In:       p.In,
		RawName:  p.Name,
	}
}

func operationToCommand(op spec.OperationDef) CommandData {
	flags := make([]FlagData, 0, len(op.Params))
	for _, p := range op.Params {
		flags = append(flags, paramToFlag(p))
	}

	bodyFields := make([]spec.BodyField, len(op.BodyFields))
	copy(bodyFields, op.BodyFields)

	// Resolve body field flag name collisions with parameter flags.
	paramNames := make(map[string]bool, len(flags))
	for _, f := range flags {
		paramNames[f.Name] = true
	}
	paramNames["body"] = true
	paramNames["all"] = true
	for i := range bodyFields {
		if paramNames[bodyFields[i].FlagName] {
			bodyFields[i].FlagName = "body-" + bodyFields[i].FlagName
			bodyFields[i].GoName = "body" + spec.ToCamel(bodyFields[i].Path)
		}
	}

	return CommandData{
		OperationID: op.OperationID,
		Use:         spec.ToKebab(op.OperationID),
		Short:       op.Summary,
		Long:        op.Description,
		Method:      op.Method,
		Path:        op.Path,
		Flags:       flags,
		BodyFields:  bodyFields,
		HasBody:     op.HasBody,
		Paginated:   op.Paginated,
	}
}

// ─── Code generation template ─────────────────────────────────────────────────

const fileTemplate = `// Code generated by scripts/gen_commands/main.go DO NOT EDIT.
// Source: {{.SchemaPath}}
//
// This file is regenerated whenever the schema changes in CI.
// Do not edit manually — run: go run scripts/gen_commands/main.go {{.SchemaPath}} <output.go>

package commands

import (
"context"
"encoding/json"
"fmt"
"strconv"

"github.com/spf13/cobra"

"github.com/FabianSchurig/bitbucket-cli/internal/client"
"github.com/FabianSchurig/bitbucket-cli/internal/handlers"
"github.com/FabianSchurig/bitbucket-cli/internal/output"
)

// Ensure imports are used.
var (
_ = context.Background
_ = fmt.Errorf
_ = json.Marshal
_ = strconv.Itoa
_ = client.NewClient
_ = handlers.Dispatch
_ = output.Format
)

// New{{.CommandName}}Command returns the "{{.CommandUse}}" cobra command with all sub-commands registered.
func New{{.CommandName}}Command() *cobra.Command {
cmd := &cobra.Command{
Use:   "{{.CommandUse}}",
Short: {{goStringLit .CommandShort}},
Long:  {{goStringLit .CommandLong}},
}

cmd.AddCommand(
{{- range .Commands}}
new{{$.CommandName}}{{toCamel .OperationID}}Cmd(),
{{- end}}
)

return cmd
}
{{range .Commands}}
// new{{$.CommandName}}{{toCamel .OperationID}}Cmd returns the "{{$.CommandUse}} {{.Use}}" cobra command.
// operationId: {{.OperationID}}
func new{{$.CommandName}}{{toCamel .OperationID}}Cmd() *cobra.Command {
{{- if or .Flags .BodyFields .HasBody .Paginated}}
var (
{{- range .Flags}}
{{.GoName}} {{.GoType}}
{{- end}}
{{- range .BodyFields}}
{{.GoName}} {{.GoType}}
{{- end}}
{{- if .HasBody}}
body string
{{- end}}
{{- if .Paginated}}
all bool
{{- end}}
)
{{- end}}

cmd := &cobra.Command{
Use:   "{{.Use}}",
Short: {{goStringLit .Short}},
Long:  {{goStringLit .Long}},
RunE: func(cmd *cobra.Command, args []string) error {
{{- range .Flags}}
{{- if .Required}}
{{- if eq .GoType "int"}}
if {{.GoName}} == 0 {
return fmt.Errorf("--{{.Name}} is required")
}
{{- else if eq .GoType "string"}}
if {{.GoName}} == "" {
return fmt.Errorf("--{{.Name}} is required")
}
{{- end}}
{{- end}}
{{- end}}
c, err := client.NewClient()
if err != nil {
return err
}
pathParams := map[string]string{
{{- range .Flags}}
{{- if eq .In "path"}}
{{- if eq .GoType "int"}}
"{{.RawName}}": strconv.Itoa({{.GoName}}),
{{- else}}
"{{.RawName}}": {{.GoName}},
{{- end}}
{{- end}}
{{- end}}
}
queryParams := map[string]string{
{{- range .Flags}}
{{- if eq .In "query"}}
{{- if eq .GoType "int"}}
"{{.RawName}}": strconv.Itoa({{.GoName}}),
{{- else if eq .GoType "bool"}}
"{{.RawName}}": strconv.FormatBool({{.GoName}}),
{{- else}}
"{{.RawName}}": {{.GoName}},
{{- end}}
{{- end}}
{{- end}}
}
{{- if .HasBody}}
if body == "" {
bodyObj := map[string]any{}
{{- range .BodyFields}}
{{- if eq .GoType "string"}}
if {{.GoName}} != "" {
handlers.SetNested(bodyObj, "{{.Path}}", {{.GoName}})
}
{{- else if eq .GoType "int"}}
if {{.GoName}} != 0 {
handlers.SetNested(bodyObj, "{{.Path}}", {{.GoName}})
}
{{- else if eq .GoType "bool"}}
if {{.GoName}} {
handlers.SetNested(bodyObj, "{{.Path}}", {{.GoName}})
}
{{- end}}
{{- end}}
if len(bodyObj) > 0 {
b, _ := json.Marshal(bodyObj)
body = string(b)
}
}
{{- end}}
{{- if not .HasBody}}
body := ""
{{- end}}
return handlers.Dispatch(context.Background(), c, handlers.Request{
					Method:      "{{.Method}}",
					URLTemplate: "{{.Path}}",
					PathParams:  pathParams,
					QueryParams: queryParams,
					Body:        body,
					All:         {{if .Paginated}}all{{else}}false{{end}},
				})
},
}

{{- range .Flags}}
cmd.Flags().{{flagFuncName .GoType}}Var(&{{.GoName}}, "{{.Name}}", {{.Default}}, "{{.Usage}}")
{{- end}}
{{- range .BodyFields}}
cmd.Flags().{{flagFuncName .GoType}}Var(&{{.GoName}}, "{{.FlagName}}", {{.Default}}, {{goStringLit .Desc}})
{{- end}}
{{- if .HasBody}}
cmd.Flags().StringVar(&body, "body", "", "Raw JSON request body (advanced)")
{{- end}}
{{- if .Paginated}}
cmd.Flags().BoolVar(&all, "all", true, "Traverse all pages (follows 'next' cursor)")
{{- end}}
return cmd
}
{{end}}
`

// ─── Template functions ───────────────────────────────────────────────────────

var templateFuncMap = template.FuncMap{
	"toCamel":     spec.ToCamel,
	"goStringLit": spec.GoStringLit,
	"flagFuncName": func(goType string) string {
		switch goType {
		case "int":
			return "Int"
		case "bool":
			return "Bool"
		default:
			return "String"
		}
	},
}

func generate(data FileData, outputPath string) error {
	tmpl, err := template.New("commands").Funcs(templateFuncMap).Parse(fileTemplate)
	if err != nil {
		return fmt.Errorf("parsing template: %w", err)
	}

	var buf bytes.Buffer
	if err := tmpl.Execute(&buf, data); err != nil {
		return fmt.Errorf("executing template: %w", err)
	}

	formatted, err := format.Source(buf.Bytes())
	if err != nil {
		return fmt.Errorf("formatting generated code: %w", err)
	}

	if err := os.WriteFile(outputPath, formatted, 0o644); err != nil {
		return fmt.Errorf("writing output file: %w", err)
	}
	return nil
}

// ─── Main ─────────────────────────────────────────────────────────────────────

func main() {
	if len(os.Args) != 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <schema.yaml> <output.go>\n", os.Args[0])
		os.Exit(1)
	}

	schemaPath := os.Args[1]
	outputPath := os.Args[2]

	schema, err := spec.LoadSchema(schemaPath)
	if err != nil {
		fmt.Fprintf(os.Stderr, "%v\n", err)
		os.Exit(1)
	}

	cmdName, cmdUse, cmdShort, cmdLong := spec.CommandMeta(schema.Info)

	operations := spec.BuildOperations(schema)
	commands := make([]CommandData, 0, len(operations))
	for _, op := range operations {
		commands = append(commands, operationToCommand(op))
	}

	data := FileData{
		SchemaPath:   schemaPath,
		CommandName:  cmdName,
		CommandUse:   cmdUse,
		CommandShort: cmdShort,
		CommandLong:  cmdLong,
		Commands:     commands,
	}

	if err := generate(data, outputPath); err != nil {
		fmt.Fprintf(os.Stderr, "%v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Generated %d commands → %s\n", len(data.Commands), outputPath)
}
